    97|function maskSecret(value: string): string {
    98|  if (!value) return 'missing';
    99|  if (value.length <= 6) return '***';
   100|  return `${value.slice(0, 4)}…${value.slice(-2)} (len=${value.length})`;
   101|}
   102|
   103|function checkProcessEnv(name: string): { present: boolean; masked: string } {
   104|  const value = (process.env[name] ?? '').trim();
   105|  return { present: value.length > 0, masked: maskSecret(value) };
   106|}
   107|
   108|async function checkOwnerVariables(name: string): Promise<{ present: boolean; masked: string }> {
   109|  try {
   110|    const value = await getIVXOwnerVariableRuntimeValue(name as never);
   111|    const present = typeof value === 'string' && value.trim().length > 0;
   112|    return { present, masked: present ? maskSecret(value) : 'missing' };
   113|  } catch {
   114|    return { present: false, masked: 'missing' };
   115|  }
