   119|
   120|async function testGitHubToken(token: string): Promise<{ ok: boolean; detail: string }> {
   121|  try {
   122|    const res = await fetch('https://api.github.com/user', {
   123|      headers: { Authorization: `Bearer ${token}`, Accept: 'application/vnd.github+json' },
   124|    });
   125|    if (res.status === 200) return { ok: true, detail: 'authenticated' };
   126|    if (res.status === 401) return { ok: false, detail: '401 — token invalid or expired' };
   127|    if (res.status === 403) return { ok: false, detail: '403 — insufficient permissions' };
   128|    return { ok: false, detail: `HTTP ${res.status}` };
   129|  } catch (err) {
   130|    return { ok: false, detail: `network: ${err instanceof Error ? err.message : String(err)}` };
   131|  }
   132|}
