   134|async function testRenderToken(token: string): Promise<{ ok: boolean; detail: string }> {
   135|  try {
   136|    const res = await fetch('https://api.render.com/v1/owners', {
   137|      headers: { Authorization: `Bearer ${token}`, Accept: 'application/json' },
   138|    });
   139|    if (res.status === 200) return { ok: true, detail: 'authenticated' };
   140|    if (res.status === 401) return { ok: false, detail: '401 — token invalid' };
   141|    return { ok: false, detail: `HTTP ${res.status}` };
   142|  } catch (err) {
   143|    return { ok: false, detail: `network: ${err instanceof Error ? err.message : String(err)}` };
   144|  }
