   149|    const res = await fetch(`${url}/rest/v1/`, {
   150|      headers: { apikey: key, Authorization: `Bearer ${key}` },
   151|    });
   152|    if (res.status === 200) return { ok: true, detail: 'accessible' };
   153|    return { ok: false, detail: `HTTP ${res.status}` };
   154|  } catch (err) {
   155|    return { ok: false, detail: `network: ${err instanceof Error ? err.message : String(err)}` };
   156|  }
