   159|// ─── Main Discovery ───────────────────────────────────────────────────
   160|
   161|export async function discoverAllCredentials(): Promise<CredentialSyncResult> {
   162|  const credentials: DiscoveredCredential[] = [];
   163|  const gaps: string[] = [];
   164|  const recommendations: string[] = [];
   165|
   166|  // Get GitHub secrets, Render env, Vercel env in parallel
   167|  const [githubSecrets, renderEnv, vercelEnv] = await Promise.all([
   168|    GitHubTool.getSecrets().catch(() => ({ ok: false, secrets: [] })),
   169|    RenderTool.getEnvVars().catch(() => ({ ok: false, envVars: [] })),
   170|    (async () => {
   171|      const projResult = await VercelTool.listProjects().catch(() => ({ ok: false, projects: [] }));
   172|      if (projResult.ok && projResult.projects?.length) {
   173|        return VercelTool.getEnvVars(projResult.projects[0].id).catch(() => ({ ok: false, envVars: [] }));
   174|      }
   175|      return { ok: false, envVars: [] };
   176|    })(),
   177|  ]);
   178|
   179|  const githubSecretNames = new Set(
   180|    (githubSecrets.secrets ?? []).map(s => s.name),
   181|  );
   182|  const renderEnvKeys = new Set(
   183|    (renderEnv.envVars ?? []).map(e => e.key),
   184|  );
   185|  const vercelEnvKeys = new Set(
   186|    (vercelEnv.envVars ?? []).map(e => e.key),
   187|  );
   188|
   189|  for (const reg of CREDENTIAL_REGISTRY) {
   190|    const [envCheck, ownerCheck] = await Promise.all([
   191|      Promise.resolve(checkProcessEnv(reg.envName)),
   192|      checkOwnerVariables(reg.name),
   193|    ]);
   194|
   195|    const sources: DiscoveredCredential['sources'] = [
   196|      { source: 'process.env', present: envCheck.present, masked: envCheck.masked },
   197|      { source: 'owner_variables', present: ownerCheck.present, masked: ownerCheck.masked },
   198|    ];
   199|
   200|    // Check if the credential name appears in GitHub secrets
   201|    if (githubSecretNames.has(reg.name)) {
   202|      sources.push({ source: 'github_secrets', present: true, masked: '*** (GitHub secret)' });
   203|    }
   204|
   205|    // Check Render env vars
   206|    if (renderEnvKeys.has(reg.name) || renderEnvKeys.has(reg.envName)) {
   207|      sources.push({ source: 'render_env', present: true, masked: '*** (Render env)' });
   208|    }
   209|
   210|    // Check Vercel env vars
   211|    if (vercelEnvKeys.has(reg.name) || vercelEnvKeys.has(reg.envName)) {
   212|      sources.push({ source: 'vercel_env', present: true, masked: '*** (Vercel env)' });
   213|    }
   214|
   215|    const anyPresent = sources.some(s => s.present);
   216|
   217|    let validation: CredentialValidation = 'unverified';
   218|    let validationDetail: string | null = null;
   219|    let tested = false;
   220|
   221|    if (!anyPresent) {
   222|      validation = 'missing';
   223|      validationDetail = 'Not found in any source';
   224|      if (reg.required) {
   225|        gaps.push(`${reg.name} (${reg.category}) — REQUIRED but missing from all sources`);
   226|      }
   227|    } else if (reg.category === 'github' && reg.name === 'GITHUB_TOKEN') {
   228|      const tokenValue = (process.env.GITHUB_TOKEN ?? '').trim();
   229|      if (tokenValue) {
   230|        const test = await testGitHubToken(tokenValue);
   231|        tested = true;
   232|        validation = test.ok ? 'valid' : 'auth_failed';
   233|        validationDetail = test.detail;
   234|      }
   235|    } else if (reg.category === 'render' && reg.name === 'RENDER_API_KEY') {
   236|      const tokenValue = (process.env.RENDER_API_KEY ?? '').trim();
   237|      if (tokenValue) {
   238|        const test = await testRenderToken(tokenValue);
   239|        tested = true;
   240|        validation = test.ok ? 'valid' : 'auth_failed';
   241|        validationDetail = test.detail;
   242|      }
   243|    } else if (reg.category === 'supabase' && reg.name === 'SUPABASE_SERVICE_ROLE_KEY') {
   244|      const url = (process.env.SUPABASE_URL ?? '').trim();
   245|      const key = (process.env.SUPABASE_SERVICE_ROLE_KEY ?? '').trim();
   246|      if (url && key) {
   247|        const test = await testSupabaseConnection(url, key);
   248|        tested = true;
   249|        validation = test.ok ? 'valid' : 'auth_failed';
   250|        validationDetail = test.detail;
   251|      }
   252|    } else if (anyPresent) {
   253|      validation = 'valid';
   254|      validationDetail = 'Present (not fully tested)';
   255|    }
   256|
   257|    credentials.push({
   258|      name: reg.name,
   259|      category: reg.category,
   260|      required: reg.required,
   261|      sources,
   262|      validation,
   263|      validationDetail,
   264|      tested,
   265|    });
   266|  }
   267|
   268|  // Build summary
   269|  const valid = credentials.filter(c => c.validation === 'valid').length;
   270|  const missing = credentials.filter(c => c.validation === 'missing').length;
   271|  const failed = credentials.filter(c => c.validation === 'auth_failed' || c.validation === 'expired' || c.validation === 'wrong_scope').length;
   272|  const unverified = credentials.filter(c => c.validation === 'unverified').length;
   273|
   274|  const requiredMissing = credentials.filter(c => c.required && c.validation === 'missing');
   275|  if (requiredMissing.length > 0) {
   276|    recommendations.push(`Configure missing required credentials: ${requiredMissing.map(c => c.name).join(', ')}`);
   277|  }
   278|
   279|  return {
   280|    ok: true,
   281|    credentials,
   282|    summary: { total: credentials.length, valid, missing, failed, unverified },
   283|    gaps,
   284|    recommendations,
   285|  };
   286|}
