    99|
   100|function parseRepoSlug(url: string): string {
   101|  const match = url.match(/github\.com[/:]([^/]+)\/([^/.\s]+?)(?:\.git)?$/i);
   102|  return match ? `${match[1]}/${match[2]}` : DEFAULT_REPO;
